  "proverbs": {
    "天气": [
      "燕子低飞蛇过道，鸡不回笼喜鹊叫，大雨不久就来到。",
      "朝霞不出门，晚霞行千里。",
      "泥鳅跳，风雨到。",
      "久晴大雾阴，久阴大雾晴。",
      "天上鱼鳞斑，晒谷不用翻。",
      "蜻蜓低飞江湖畔，即将有雨在眼前。",
      "大雁北飞天将暖，燕子南归气转寒。",
      "一场秋雨一场寒，十场秋雨要穿棉。",
      "日落胭脂红，无雨必有风。",
      "夜里星光明，明朝依旧晴。",
      "今夜露水重，明天太阳红。",
      "有雨山戴帽，无雨山没腰。"
    ],
    "帮助": [
      "花要叶扶，人要人帮。",
      "赠人玫瑰，手有余香。",
      "帮助别人的人，能得到别人的帮助。",
      "诚心能叫石头落泪，实意能叫枯木发芽。"
    ],
    "祖国风光": [
      "上有天堂，下有苏杭。",
      "峨眉天下秀，青城天下幽，三峡天下雄，剑门天下险。",
      "五岳归来不看山，黄山归来不看岳。",
      "桂林山水甲天下，阳朔山水甲桂林。"
    ],
    "思想方法": [
      "绳在细处断，冰在薄处裂。",
      "亲身下河知深浅，亲口尝梨知酸甜。",
      "莫看江面平如镜，要看水底万丈深。",
      "花盆里长不出苍松，鸟笼里飞不出雄鹰。",
      "日日行，不怕千万里；常常做，不怕千万事。"
    ],
    "团结": [
      "人心齐，泰山移。",
      "人多计谋广，柴多火焰高。",
      "一根筷子容易折，一把筷子难折断。",
      "树多成林不怕风，线多搓绳挑千斤。",
      "一花独放不是春，百花齐放春满园。"
    ]
  },
