  "sentencePatterns": [
    {
      "id": 1,
      "lines": [
        "幸福是“临行密密缝，意恐迟迟归”的牵挂；",
        "幸福是“春种一粒粟，秋收千颗子”的收获；",
        "幸福是“采菊东篱下，悠然见南山”的闲适；",
        "幸福是“不畏浮云遮望眼，只缘身在最高层”的追求。"
      ]
    },
    {
      "id": 2,
      "lines": [
        "朋友是什么，朋友是快乐日子里的一把吉它，尽情地为你弹奏生活的愉悦；",
        "朋友是忧伤日子里的一股春风，轻轻地为你拂去心中的愁云。",
        "朋友是成功道路上的一位良师，热情地将你引向阳光的地带。",
        "朋友是失败苦闷中的一盏明灯，默默地为你驱赶心灵的阴霾。"
      ]
    },
    {
      "id": 3,
      "lines": [
        "爱心是冬日里的一片阳光，使饥寒交迫的人分外感到人间的温暖。",
        "爱心是沙漠中的一泓泉水，使濒临绝境的人重新看到生活的希望。",
        "爱心是夜空中的一轮明月，使孤苦无依的人即刻获得心灵的慰藉。",
        "爱心是春天里的一场细雨，使心灵枯萎的人特别感到情感的滋润。",
        "爱心是夏日里的一阵清风，使心急如焚的人感到无比的凉爽。",
        "爱心是黑夜里的一座灯塔，使迷失方向的航船找到停靠的港湾。"
      ]
    },
    {
      "id": 4,
      "lines": [
        "事业说：人生就是建筑历史的一块砖石。",
        "友谊说：人生就是帮助别人攀登的阶梯。",
        "奋斗说：人生就是与风浪搏击的双桨。",
        "勤奋说：人生就是耕耘大自然的老黄牛。",
        "困难说：人生就是在暗礁中行进的船。",
        "挫折说：人生就是那条坎坷曲折的小路。"
      ]
    },
    {
      "id": 5,
      "lines": [
        "假如生命是一株小草，我愿为春天献上一点嫩绿。",
        "假如生命是一棵大树，我愿为大地撒下一片绿阴；",
        "假如生命是一朵鲜花，我愿为世界奉上一缕馨香；",
        "假如生命是一枚果实，我愿为人间留下一丝甘甜。"
      ]
    },
    {
      "id": 6,
      "lines": [
        "风从水上走过，留下了粼粼波纹；",
        "阳光从云中穿过，留下了缕缕温暖；",
        "骆驼从沙漠走过，留下了深深蹄印；",
        "哨鸽从天空飞过，留下了声声欢韵；",
        "岁月从树林中走过，留下了圈圈年轮……",
        "啊，朋友，我们从时代的舞台走过，留下了什么呢？"
      ]
    },
    {
      "id": 7,
      "lines": [
        "即使我们只是一支蜡烛，也应该“蜡炬成灰泪始干”；",
        "即使我们只是一只春蚕，也应该“春蚕到死丝方尽”；",
        "即使我们只是一片树叶，也应该“化作春泥更护花”；",
        "即使我们只是一根火柴，也要在关键时刻有一次闪耀；",
        "即使我们只是一朵花，也要给人们带来一丝清香；",
        "即使我们只是一颗星星，也要在黑暗中闪出自己的光芒；",
        "即使我们只是一滴水，也要在生命的旅途中作叮咚的脆响；",
        "即使我们只是一棵小草，也要给大地带来一点绿色。"
      ]
    },
    {
      "id": 8,
      "lines": [
        "历史是一本书，时间是一支笔；",
        "历史是一艘船，时间是一张网；",
        "历史是一幅画，时间是绚丽的色彩；",
        "历史是一座高山，时间是嶙峋的巨石；",
        "历史是一棵大树，时间是繁茂的枝叶；",
        "历史是一条长河，时间是涌动着的波涛；",
        "历史是一首曲谱，时间是跳动着的音符。"
      ]
    },
    {
      "id": 9,
      "lines": [
        "人生的意义在于奉献而不在于索取。",
        "如果你是一棵大树，就撒下一片阴凉；",
        "如果你是一泓清泉，就滋润一方土地；",
        "如果你是一棵小草，就增添一份绿意；",
        "如果你是一颗星星，就点缀一角天空；",
        "如果你是一朵鲜花，就装点一分春色。"
      ]
    },
    {
      "id": 10,
      "lines": [
        "如果你是大河，何必在乎别人把你说成小溪；",
        "如果你是峰峦，何必在乎别人把你当成平地；",
        "如果你是春天，何必为一瓣花朵的凋零而叹息；",
        "如果你是种子，何必为还没有结出果实而着急；",
        "如果你就是你，那就静静微笑沉默不语。"
      ]
    },
    {
      "id": 11,
      "lines": [
        "爱读书，是一种美德。世界上有大成就的人，对人类有特殊贡献的人，几乎都是爱读书的人。",
        "读书，使人思维活跃，聪颖智慧；",
        "读书，使人胸襟开阔，豁达晓畅；",
        "读书，使人目光远大，志存高远；",
        "读书，使人思想插上翅膀，感情绽开花蕾。"
      ]
    },
    {
      "id": 12,
      "lines": [
        "生活是一首美妙动听的歌，我们要学会欣赏。",
        "生活是一艘扬帆远航的船，我们要学会驾驶。",
        "生活是一首豪壮抒情的诗，我们要学会朗诵。",
        "生活是一幅五彩缤纷的图画，我们要学会鉴赏。",
        "生活是一本丰富多彩的书，我们要学会阅读。"
      ]
    },
    {
      "id": 13,
      "lines": [
        "爱心是一片照射在冬日的阳光，使贫寒交迫的人感到人间的温暖；",
        "爱心是一眼流淌于夏日的甘泉，使心田干涸的人得到真正的滋润；",
        "爱心是一个飞翔在人间的天使，使饱受苦难的人获得幸福的沐浴。"
      ]
    },
    {
      "id": 14,
      "lines": [
        "人生如一支歌，应该多一些激昂的旋律，少一些萎靡的音符；",
        "人生如一首诗，应该多一些热烈的抒情，少一些愁苦的叹息；",
        "人生如一幅画，应该多一点亮丽的色彩，少一些灰暗的色调。"
      ]
    },
    {
      "id": 15,
      "lines": [
        "假如我是个画家，我就要用各种彩色，点染出她们的清扬的眉宇和绚丽的服装。",
        "假如我是个雕刻家，我就要在玉石上模拟出她们的充满了活力的苗条灵动的身形。",
        "假如我是个歌手，我就要用优美的旋律和甜美的歌声来赞美她们婀娜的舞姿和充满魅力的面庞。",
        "假如我是个摄影师，我就要用光彩和色彩拍下她们勃发的活力和妩媚的身姿。"
      ]
    },
    {
      "id": 16,
      "lines": [
        "青春是一种令人羡慕的资本。",
        "凭着健壮的体魄，你可以支撑起一方蔚蓝的天空；",
        "凭着顽强的毅力，你可以攀登上一座巍峨的高山；",
        "凭着旺盛的精力，你可以开垦出一片肥沃的土地；",
        "凭着超人的智慧，你可以描绘出一幅精美的画卷。"
      ]
    },
    {
      "id": 17,
      "lines": [
        "其实天不暗，阴云终要散；",
        "其实海不宽，此岸连彼岸；",
        "其实山不险，条条路可攀；",
        "其实路不远，一切会如愿。",
        "艰难困苦的日子里我为你祈祷，请你保重每一天。"
      ]
    },
    {
      "id": 18,
      "lines": [
        "让我们来做花的事业吧，把花香传给别人；",
        "让我们来做叶的事业吧，把花顶过自己的身躯；",
        "让我们来做根的事业吧，把养分输送给叶和花；",
        "让我们来做土的事业吧，把千万棵花孕育得根深叶茂。"
      ]
    },
    {
      "id": 19,
      "lines": [
        "花朵把春天的门推开；",
        "绿荫把夏天的门推开；",
        "硕果把秋天的门推开；",
        "飞雪把冬天的门推开；",
        "真诚把友谊的门推开。"
      ]
    },
    {
      "id": 20,
      "lines": [
        "只有启程，才会到达理想的目的地；",
        "只有拼搏，才会获得辉煌的成功；",
        "只有播种，才会有收获；",
        "只有追求，才会品味堂堂正正的人生。"
      ]
    }
  ],
