  "rhetoric": [
    {
      "id": 1,
      "name": "比喻",
      "definition": "用具体的、浅显的事物来说明抽象的、深奥的事物。分明喻、暗喻、借喻。",
      "types": [
        "明喻：甲像乙（像、似、若、犹、好像、仿佛）",
        "暗喻：甲是乙（是、成为、变成、化作）",
        "借喻：只出现喻体",
        "例：燕雀安知鸿鹄之志！（借喻）"
      ],
      "examples": []
    },
    {
      "id": 2,
      "name": "借代",
      "definition": "借用与事物有密切关系的名称替代。",
      "types": [
        "以部分代全体：不拿群众一针一线。",
        "以具体代抽象：不要大锅饭。",
        "以特征代本体：花白胡子坐在墙角里。",
        "以专名代通称：千万个雷锋活跃在祖国大地上。"
      ],
      "examples": []
    },
    {
      "id": 3,
      "name": "比拟",
      "definition": "",
      "types": [
        "拟人：把物当人写（蜡炬成灰泪始干）",
        "拟物：把人当物写（做人既不可翘尾巴）"
      ],
      "examples": []
    },
    {
      "id": 4,
      "name": "夸张",
      "definition": "扩大或缩小描述。",
      "types": [
        "扩大夸张：白发三千丈",
        "缩小夸张：芝麻粒儿大的事",
        "超前夸张：太阳刚一出来，地上已经像下了火"
      ],
      "examples": []
    },
    {
      "id": 5,
      "name": "对比",
      "definition": "把两种事物或同一事物的两个方面并举比较。",
      "types": [],
      "examples": [
        "先天下之忧而忧，后天下之乐而乐",
        "朱门酒肉臭，路有冻死骨"
      ]
    },
    {
      "id": 6,
      "name": "对偶",
      "definition": "结构相同、字数相等的短语或句子对称排列。",
      "types": [],
      "examples": [
        "满招损，谦受益",
        "横眉冷对千夫指，俯首甘为孺子牛"
      ]
    },
    {
      "id": 7,
      "name": "排比",
      "definition": "三个或三个以上结构相似、语气一致的短语或句子连用。",
      "types": [],
      "examples": []
    },
    {
      "id": 8,
      "name": "反复",
      "definition": "重复使用同一词语或句子。",
      "types": [
        "连续反复：前进！前进！前进！",
        "间隔反复：敌人从哪里进攻，我们就要它在哪里灭亡……"
      ],
      "examples": []
    },
    {
      "id": 9,
      "name": "反语",
      "definition": "说反话，字面与实际意思相反。",
      "types": [],
      "examples": [
        "“友邦人士”从此可以不必“惊诧莫名”。"
      ]
    },
    {
      "id": 10,
      "name": "反问",
      "definition": "用疑问形式表达确定意思，不需回答。",
      "types": [],
      "examples": [
        "难道中学老师和小姐骑自行车还成体统吗？"
      ]
    },
    {
      "id": 11,
      "name": "设问",
      "definition": "自问自答。",
      "types": [],
      "examples": [
        "这七人端的是谁？不是别人，原来正是晁盖……"
      ]
    },
    {
      "id": 12,
      "name": "顶针（顶真）",
      "definition": "上句结尾与下句开头相同。",
      "types": [],
      "examples": [
        "归来见天子，天子坐明堂。"
      ]
    },
    {
      "id": 13,
      "name": "回环",
      "definition": "顺读逆读都一样。",
      "types": [],
      "examples": [
        "响水潭中潭水响；黄金谷里谷金黄。",
        "客上天然居，居然天上客；人过大佛寺，寺佛大过人。"
      ]
    }
  ],
